/* ============================================================
   SPLASH SCREEN
   ============================================================ */
function enterSite() {
  // Play the song
  const audio = document.getElementById('splash-audio');
  if (audio) {
    audio.volume = 0.85;
    audio.play().catch(() => {});
  }

  // Animate splash out
  const splash = document.getElementById('splash-screen');
  splash.classList.add('exiting');
  setTimeout(() => {
    splash.style.display = 'none';
  }, 1100);
}

// Splash petals
document.addEventListener('DOMContentLoaded', () => {
  const container = document.getElementById('splash-petals');
  if (!container) return;
  function createSplashPetal() {
    const p = document.createElement('div');
    p.className = 'petal';
    const size = 4 + Math.random() * 7;
    p.style.cssText = `
      width:${size}px; height:${size}px;
      left:${Math.random() * 100}%;
      animation-duration:${10 + Math.random() * 10}s;
      animation-delay:${Math.random() * 4}s;
      border-radius: ${Math.random() > 0.5 ? '50% 0 50% 0' : '50%'};
      opacity:0;
    `;
    container.appendChild(p);
    setTimeout(() => p.remove(), 22000);
  }
  const splashPetalInterval = setInterval(createSplashPetal, 700);
  for (let i = 0; i < 10; i++) setTimeout(createSplashPetal, i * 350);
  // Stop petals once splash is gone
  setTimeout(() => clearInterval(splashPetalInterval), 15000);
});

/* ============================================================
   SHARED: THEME TOGGLE
   ============================================================ */
function toggleTheme() {
  const html = document.documentElement;
  const icons = document.querySelectorAll('.theme-icon');
  html.dataset.theme = html.dataset.theme === 'dark' ? 'light' : 'dark';
  const isDark = html.dataset.theme === 'dark';
  icons.forEach(i => i.textContent = isDark ? '☀️' : '🌙');
}

/* ============================================================
   SHARED: BACKGROUND EFFECTS (STARS + PETALS)
   ============================================================ */
function initStars(containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  for (let i = 0; i < 80; i++) {
    const s = document.createElement('div');
    s.className = 'star';
    const size = Math.random() * 2.5 + 0.5;
    s.style.cssText = `
      width:${size}px; height:${size}px;
      top:${Math.random() * 100}%;
      left:${Math.random() * 100}%;
      animation-duration:${2 + Math.random() * 4}s;
      animation-delay:${Math.random() * 4}s;
    `;
    el.appendChild(s);
  }
}

function initPetals(containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  function createPetal() {
    const p = document.createElement('div');
    p.className = 'petal';
    const size = 4 + Math.random() * 8;
    p.style.cssText = `
      width:${size}px; height:${size}px;
      left:${Math.random() * 100}%;
      animation-duration:${8 + Math.random() * 10}s;
      animation-delay:${Math.random() * 5}s;
      border-radius: ${Math.random() > 0.5 ? '50% 0 50% 0' : '50%'};
      opacity:0;
    `;
    el.appendChild(p);
    setTimeout(() => p.remove(), 20000);
  }
  setInterval(createPetal, 600);
  for (let i = 0; i < 12; i++) setTimeout(createPetal, i * 300);
}

/* ============================================================
   SPA NAVIGATION
   ============================================================ */
function showPage(pageId) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  const page = document.getElementById(pageId);
  if (page) {
    page.classList.add('active');
    window.scrollTo(0, 0);
  }
  if (pageId === 'page-calendar') initCalendar();
}

/* ============================================================
   PAGE: INDEX
   ============================================================ */
function initIndex() {
  initStars('stars-index');
  initPetals('petals-index');
}

/* ============================================================
   PAGE: STORY
   ============================================================ */
function initStory() {
  // Scroll reveal for timeline chapters
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
  }, { threshold: 0.1 });
  document.querySelectorAll('.chapter').forEach(c => obs.observe(c));
}

function triggerUpload(slot) {
  slot.querySelector('input[type=file]').click();
}

function loadPhoto(input) {
  if (!input.files[0]) return;
  const slot = input.closest('.photo-slot');
  const reader = new FileReader();
  reader.onload = e => {
    let img = slot.querySelector('img');
    if (!img) { img = document.createElement('img'); slot.appendChild(img); }
    img.src = e.target.result;
    slot.querySelector('.photo-hint').style.display = 'none';
    slot.querySelector('.photo-label').style.display = 'none';
  };
  reader.readAsDataURL(input.files[0]);
}

