let current = 0, score = 0, answered = false;

function showScreen(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
}

function startGame() {
  current = 0; score = 0;
  showScreen('intro-screen');
  showScreen('quiz-screen');
  loadQuestion();
}

function loadQuestion() {
  const q = questions[current];
  document.getElementById('q-num').textContent = `Question ${current + 1} of ${questions.length}`;
  document.getElementById('q-text').textContent = q.q;
  document.getElementById('progress').style.width = `${(current / questions.length) * 100}%`;
  const fb = document.getElementById('feedback');
  fb.textContent = ''; fb.classList.remove('show');
  document.getElementById('btn-next').style.display = 'none';
  answered = false;
  const opts = document.getElementById('options');
  opts.innerHTML = '';
  q.opts.forEach((o, i) => {
    const btn = document.createElement('button');
    btn.className = 'opt';
    btn.innerHTML = `<span>${o}</span>`;
    btn.onclick = () => selectAnswer(i);
    opts.appendChild(btn);
  });
}

function selectAnswer(i) {
  if (answered) return;
  answered = true;
  const q = questions[current];
  const btns = document.querySelectorAll('.opt');
  btns.forEach((b, idx) => {
    b.disabled = true;
    if (idx === q.answer) b.classList.add('correct');
    else if (idx === i && i !== q.answer) b.classList.add('wrong');
  });
  if (i === q.answer) score++;
  const fb = document.getElementById('feedback');
  fb.textContent = (i === q.answer ? '✓  ' : '✗  ') + q.fb;
  fb.classList.add('show');
  document.getElementById('btn-next').style.display = 'inline-block';
}

function nextQuestion() {
  current++;
  if (current >= questions.length) { showResults(); return; }
  loadQuestion();
}

function showResults() {
  document.getElementById('progress').style.width = '100%';
  const pct = score / questions.length;
  let icon, title, msg;
  if (pct === 1)       { icon = '🏆'; title = 'Perfect score!';  msg = "You know everything about us. I love you so much it's actually ridiculous. ❤️"; }
  else if (pct >= 0.75){ icon = '💕'; title = 'Almost perfect!'; msg = "You know me so well — just a few surprises left up my sleeve. 😉"; }
  else if (pct >= 0.5) { icon = '😄'; title = 'Pretty good!';    msg = "Half of our story is already in your heart. The other half we'll keep writing. 🌸"; }
  else                 { icon = '🙈'; title = 'Room to grow!';   msg = "That's okay — the best part of love is still learning each other, every single day. 💌"; }
  document.getElementById('result-icon').textContent = icon;
  document.getElementById('result-score').textContent = `${score}/${questions.length}`;
  document.getElementById('result-title').textContent = title;
  document.getElementById('result-msg').textContent = msg;
  showScreen('result-screen');
}

function restartGame() { startGame(); }

function initGame() {
  showScreen('game-hub');
}


