let currentLang = 'en';

function toggleLang() {
  currentLang = currentLang === 'en' ? 'ar' : 'en';
  applyLang();
}

function applyLang() {
  const t = translations[currentLang];
  const isAr = currentLang === 'ar';
  const html = document.documentElement;

  // Direction & font
  html.setAttribute('dir', isAr ? 'rtl' : 'ltr');
  html.setAttribute('lang', isAr ? 'ar' : 'en');

  // Update lang button labels
  document.querySelectorAll('.lang-icon').forEach(el => {
    el.textContent = isAr ? 'EN' : 'ع';
  });

  // Helper to set innerHTML safely
  function set(sel, key) {
    document.querySelectorAll(sel).forEach(el => { if (t[key]) el.innerHTML = t[key]; });
  }

  // Index page
  set('.date-tag', 'date-tag');
  set('.main-title', 'main-title');
  set('.subtitle', 'subtitle');
  set('.footer', 'footer-txt');

  const cards = document.querySelectorAll('.card');
  [1,2,3].forEach((n, i) => {
    const card = cards[i];
    if (!card) return;
    card.querySelector('.card-num').textContent = t['card-num-' + n];
    card.querySelector('.card-title').textContent = t['card-title-' + n];
    card.querySelector('.card-desc').textContent = t['card-desc-' + n];
    card.querySelector('.card-arrow').textContent = t['card-arrow-' + n];
  });

  // Nav titles
  const navTitles = document.querySelectorAll('.nav-title');
  const navKeys = ['nav-story', 'nav-game', 'nav-letter'];
  navTitles.forEach((el, i) => { if (navKeys[i]) el.textContent = t[navKeys[i]]; });

  // Back links
  document.querySelectorAll('.nav-back').forEach(el => el.textContent = t['back']);

  // Story page
  set('.hero-eyebrow', 'hero-eyebrow');
  set('.hero-title', 'hero-title');
  set('.hero-sub', 'hero-sub');
  set('.scroll-hint', 'scroll-hint');

  const chapters = document.querySelectorAll('.chapter');
  [1,2,3,4,5].forEach((n, i) => {
    const ch = chapters[i];
    if (!ch) return;
    const d = ch.querySelector('.chapter-date');
    const h = ch.querySelector('.chapter-heading');
    const p = ch.querySelector('.chapter-text');
    if (d) d.textContent = t['ch' + n + '-date'];
    if (h) h.textContent = t['ch' + n + '-heading'];
    if (p) p.textContent = t['ch' + n + '-text'];
  });

  const endHeart = document.querySelector('.end-heart');
  if (endHeart) endHeart.innerHTML = '<span>♥</span><br>' + t['end-heart-txt'];

  // Game page
  set('.intro-eyebrow', 'intro-eyebrow');
  set('.intro-title', 'intro-title');
  set('.intro-sub', 'intro-sub');
  document.querySelectorAll('.btn-start').forEach(el => el.textContent = t['btn-start']);

  // Letter page
  set('.letter-eyebrow', 'letter-eyebrow');
  set('.letter-title', 'letter-title');
  set('.letter-lead', 'letter-lead');
  set('.signature', 'signature');
  set('.letter-footer', 'letter-footer-txt');
}

