// ── Calendar state ───────────────────────────────────────────────────
let calYear, calMonth; // current view (0-based month like JS Date)

function initCalendar() {
  const now = new Date();
  // Default view: jump to the month containing our anniversary if it's
  // within 60 days, otherwise show current month.
  calYear  = now.getFullYear();
  calMonth = now.getMonth(); // 0-based

  initStars("cal-stars");
  initPetals("cal-petals");
  renderCalendar();
}

function calPrevMonth() {
  calMonth--;
  if (calMonth < 0) { calMonth = 11; calYear--; }
  renderCalendar();
}

function calNextMonth() {
  calMonth++;
  if (calMonth > 11) { calMonth = 0; calYear++; }
  renderCalendar();
}

function renderCalendar() {
  const label = document.getElementById("cal-month-label");
  const grid  = document.getElementById("cal-grid");
  if (!label || !grid) return;

  const monthNames = [
    "January","February","March","April","May","June",
    "July","August","September","October","November","December"
  ];
  label.textContent = `${monthNames[calMonth]} ${calYear}`;

  const today     = new Date();
  const firstDay  = new Date(calYear, calMonth, 1).getDay(); // 0=Sun
  const daysInMonth = new Date(calYear, calMonth + 1, 0).getDate();

  grid.innerHTML = "";

  // Leading empty cells
  for (let i = 0; i < firstDay; i++) {
    const blank = document.createElement("div");
    blank.className = "cal-cell cal-blank";
    grid.appendChild(blank);
  }

  // Day cells
  for (let d = 1; d <= daysInMonth; d++) {
    const special = getSpecialDate(calMonth + 1, d, calYear);
    const isToday = (
      d === today.getDate() &&
      calMonth === today.getMonth() &&
      calYear  === today.getFullYear()
    );

    const cell = document.createElement("div");
    cell.className = "cal-cell" +
      (special  ? " cal-special" : "") +
      (isToday  ? " cal-today"   : "");

    if (special) {
      cell.style.setProperty("--sp-color", special.color || "var(--accent)");
      cell.innerHTML = `
        <span class="cal-day-num">${d}</span>
        <span class="cal-special-emoji">${special.emoji}</span>
        <span class="cal-special-label">${special.label}</span>
      `;
      cell.addEventListener("click", () => openStoryModal(special, d, calMonth + 1, calYear));
    } else {
      cell.innerHTML = `<span class="cal-day-num">${d}</span>`;
    }

    grid.appendChild(cell);
  }
}

// Returns matching specialDate entry or null
function getSpecialDate(month, day, year) {
  return specialDates.find(s =>
    s.month === month &&
    s.day   === day   &&
    (s.year === null || s.year === year)
  ) || null;
}

// ── Story Modal ──────────────────────────────────────────────────────
function openStoryModal(special, day, month, year) {
  const monthNames = [
    "January","February","March","April","May","June",
    "July","August","September","October","November","December"
  ];
  const displayYear = special.startYear || year;
  const dateStr = `${monthNames[month - 1]} ${day}${ordinal(day)}, ${displayYear}`;

  // Anniversary badge: how many years since startYear
  let anniversaryHtml = "";
  if (special.startYear && year > special.startYear) {
    const n = year - special.startYear;
    const suffix = n === 1 ? "st" : n === 2 ? "nd" : n === 3 ? "rd" : "th";
    anniversaryHtml = `<div class="story-modal-anniversary">${n}${suffix} anniversary 🎉</div>`;
  }

  const inner = document.getElementById("story-modal-inner");
  const backdrop = document.getElementById("story-modal-backdrop");
  const modal    = document.getElementById("story-modal");
  if (!inner || !modal) return;

  // Build images HTML if any exist
  const imagesHtml = (special.images && special.images.length)
    ? `<div class="story-modal-images">
        ${special.images.map(src =>
          `<img src="${src}" alt="Memory" class="story-modal-img" loading="lazy">`
        ).join("")}
       </div>`
    : "";

  // Convert newlines to paragraphs, *text* to <em>
  const storyHtml = special.story
    .split(/\n{2,}/)
    .map(para => `<p>${para.trim().replace(/\*(.*?)\*/g, "<em>$1</em>")}</p>`)
    .join("");

  inner.innerHTML = `
    <div class="story-modal-date-tag">${dateStr}</div>
    <div class="story-modal-emoji">${special.emoji} ${anniversaryHtml}</div>
    <h2 class="story-modal-title">${special.title}</h2>
    <div class="story-modal-body">${storyHtml}</div>
    ${imagesHtml}
    <div class="story-modal-label">${special.label}</div>
  `;

  // Apply the special colour as an accent
  modal.style.setProperty("--sp-color", special.color || "var(--accent)");

  backdrop.classList.add("open");
  modal.classList.add("open");
  document.body.style.overflow = "hidden";
}

function closeStoryModal() {
  const backdrop = document.getElementById("story-modal-backdrop");
  const modal    = document.getElementById("story-modal");
  if (!backdrop || !modal) return;
  backdrop.classList.remove("open");
  modal.classList.remove("open");
  document.body.style.overflow = "";
}

function ordinal(n) {
  if (n > 3 && n < 21) return "th";
  switch (n % 10) {
    case 1: return "st";
    case 2: return "nd";
    case 3: return "rd";
    default: return "th";
  }
}
