let gdCurrent = 0, gdScore = 0;

function initGuessDate() {
  gdCurrent = 0; gdScore = 0;
  document.getElementById('guessdate-play').style.display = 'none';
  document.getElementById('guessdate-result').style.display = 'none';
  document.getElementById('guessdate-start-btns').style.display = 'block';
  document.getElementById('gd-score').textContent = '0';
  document.getElementById('gd-round').textContent = '1 / ' + gdEvents.length;
}

function startGuessDate() {
  document.getElementById('guessdate-start-btns').style.display = 'none';
  document.getElementById('guessdate-play').style.display = 'block';
  loadGuessDate();
}

function loadGuessDate() {
  const ev = gdEvents[gdCurrent];
  document.getElementById('gd-round').textContent = (gdCurrent + 1) + ' / ' + gdEvents.length;
  document.getElementById('gd-event').textContent = ev.event;
  document.getElementById('gd-hint').textContent = ev.hint;
  document.getElementById('gd-day').value = '';
  document.getElementById('gd-month').value = '';
  document.getElementById('gd-year').value = '';
  document.getElementById('gd-feedback').textContent = '';
  document.getElementById('gd-feedback').classList.remove('show');
  document.getElementById('gd-next-btn').style.display = 'none';
  document.getElementById('gd-submit-btn').style.display = 'inline-block';
}

function submitGuessDate() {
  const day   = parseInt(document.getElementById('gd-day').value);
  const month = parseInt(document.getElementById('gd-month').value);
  const year  = parseInt(document.getElementById('gd-year').value);
  if (!day || !month || !year) { alert('Please pick a day, month and year!'); return; }
  const ev = gdEvents[gdCurrent];
  const fb = document.getElementById('gd-feedback');
  const monthNames = ['','January','February','March','April','May','June','July','August','September','October','November','December'];
  const exactDay = day === ev.day, exactMonth = month === ev.month, exactYear = year === ev.year;
  let pts = 0;
  if (exactDay && exactMonth && exactYear)          { pts = 4; }
  else if (exactMonth && exactYear)                  { pts = 3; }
  else if (exactYear && Math.abs(month - ev.month) <= 1) { pts = 2; }
  else if (exactYear)                                { pts = 1; }
  gdScore += pts;
  document.getElementById('gd-score').textContent = gdScore;
  const correctDate = monthNames[ev.month] + ' ' + ev.day + ', ' + ev.year;
  if (pts === 4) {
    fb.textContent = '✓ Perfect! ' + ev.fb;
  } else if (pts === 3) {
    fb.textContent = '✓ Right month & year! It was the ' + ev.day + '. ' + ev.fb;
  } else if (pts === 2) {
    fb.textContent = '✓ Right year, close month! It was ' + correctDate + '. ' + ev.fb;
  } else if (pts === 1) {
    fb.textContent = '~ Right year at least! It was ' + correctDate + '. ' + ev.fb;
  } else {
    fb.textContent = '✗ It was ' + correctDate + '. ' + ev.fb;
  }
  fb.classList.add('show');
  document.getElementById('gd-submit-btn').style.display = 'none';
  document.getElementById('gd-next-btn').style.display = 'inline-block';
}

function nextGuessDate() {
  gdCurrent++;
  if (gdCurrent >= gdEvents.length) { showGuessDateResult(); return; }
  loadGuessDate();
}

function showGuessDateResult() {
  document.getElementById('guessdate-play').style.display = 'none';
  document.getElementById('guessdate-result').style.display = 'block';
  const max = gdEvents.length * 4;
  const pct = gdScore / max;
  let icon, title, msg;
  if (pct === 1)        { icon = '🏆'; title = 'Perfect memory!'; msg = "You remember every moment like it was yesterday. That means everything. ❤️"; }
  else if (pct >= 0.75) { icon = '💕'; title = 'Amazing!'; msg = "You hold our memories so close to your heart. I love you for that. 🌸"; }
  else if (pct >= 0.4)  { icon = '😄'; title = 'Pretty good!'; msg = "You got the big moments right — the details we'll just keep making together. 💫"; }
  else                   { icon = '🙈'; title = 'Dates are hard!'; msg = "But every single one of those days was magical — and you were there for all of them. 💌"; }
  document.getElementById('gd-result-icon').textContent = icon;
  document.getElementById('gd-result-score').textContent = gdScore + ' / ' + max;
  document.getElementById('gd-result-title').textContent = title;
  document.getElementById('gd-result-msg').textContent = msg;
}


