// ── State ──
let playerCurrentPlaylist = null;
let playerCurrentIndex    = 0;
let playerIsPlaying       = false;
let playerShuffle         = false;
let playerRepeat          = false;
let playerShuffleOrder    = [];

const audio = () => document.getElementById('player-audio');

// ── Init ──
function initPlayer() {
  document.getElementById('player-playlist-select').style.display = 'block';
  document.getElementById('player-main').style.display = 'none';
  renderPlaylistCards();
}

function renderPlaylistCards() {
  const list = document.getElementById('pl-list');
  list.innerHTML = '';
  playlists.forEach(pl => {
    const card = document.createElement('button');
    card.className = 'pl-card';
    card.style.setProperty('--pl-color', pl.color);
    card.innerHTML = `
      <span class="pl-card-emoji">${pl.emoji}</span>
      <div class="pl-card-info">
        <p class="pl-card-name">${pl.name}</p>
        <p class="pl-card-desc">${pl.desc}</p>
        <p class="pl-card-count">${pl.tracks.length} songs</p>
      </div>
      <span class="pl-card-arrow">▶</span>
    `;
    card.onclick = () => openPlaylist(pl.id);
    list.appendChild(card);
  });
}

function openPlaylist(id) {
  playerCurrentPlaylist = playlists.find(p => p.id === id);
  playerCurrentIndex    = 0;
  playerShuffleOrder    = buildShuffleOrder(playerCurrentPlaylist.tracks.length);
  document.getElementById('player-playlist-select').style.display = 'none';
  document.getElementById('player-main').style.display = 'block';
  renderTracklist();
  loadTrack(0);
}

function showPlaylistSelect() {
  stopPlayer();
  document.getElementById('player-playlist-select').style.display = 'block';
  document.getElementById('player-main').style.display = 'none';
}

// ── Track management ──
function loadTrack(index) {
  if (!playerCurrentPlaylist) return;
  // Stop splash audio if still playing
  const splashAudio = document.getElementById('splash-audio');
  if (splashAudio && !splashAudio.paused) {
    splashAudio.pause();
    splashAudio.currentTime = 0;
  }
  const tracks = playerCurrentPlaylist.tracks;
  playerCurrentIndex = ((index % tracks.length) + tracks.length) % tracks.length;
  const t = tracks[playerCurrentIndex];
  const a = audio();

  // Update UI
  document.getElementById('player-song-title').textContent = t.title;
  document.getElementById('player-artist').textContent     = t.artist;
  document.getElementById('player-playlist-label').textContent = playerCurrentPlaylist.emoji + ' ' + playerCurrentPlaylist.name;
  document.getElementById('player-art-note').textContent   = t.note || '♪';
  document.getElementById('player-art').style.setProperty('--pl-color', playerCurrentPlaylist.color);
  document.getElementById('player-art-glow').style.background =
    'radial-gradient(ellipse at 50% 50%, ' + playerCurrentPlaylist.color + '33 0%, transparent 70%)';

  // Progress reset
  document.getElementById('player-progress-fill').style.width  = '0%';
  document.getElementById('player-progress-thumb').style.left  = '0%';
  document.getElementById('player-current').textContent = '0:00';
  document.getElementById('player-duration').textContent = '0:00';

  // Load audio
  a.src = t.file;
  a.load();
  if (playerIsPlaying) {
    a.play().catch(() => {});
  }

  highlightTrack();
}

function renderTracklist() {
  if (!playerCurrentPlaylist) return;
  const list = document.getElementById('player-tracklist');
  list.innerHTML = '';
  playerCurrentPlaylist.tracks.forEach((t, i) => {
    const item = document.createElement('div');
    item.className = 'track-item' + (i === playerCurrentIndex ? ' active' : '');
    item.id = 'track-' + i;
    item.innerHTML = `
      <span class="track-num">${i + 1}</span>
      <div class="track-info">
        <p class="track-title">${t.title}</p>
        <p class="track-artist">${t.artist}</p>
      </div>
      <span class="track-play-icon">▶</span>
    `;
    item.onclick = () => { loadTrack(i); if (!playerIsPlaying) togglePlay(); };
    list.appendChild(item);
  });
}

function highlightTrack() {
  document.querySelectorAll('.track-item').forEach((el, i) => {
    el.classList.toggle('active', i === playerCurrentIndex);
  });
}

// ── Playback controls ──
function togglePlay() {
  const a = audio();
  if (playerIsPlaying) {
    a.pause();
    playerIsPlaying = false;
  } else {
    a.play().catch(() => {});
    playerIsPlaying = true;
  }
  updatePlayPauseIcon();
  updateArtSpin();
}

function updatePlayPauseIcon() {
  document.getElementById('icon-play').style.display  = playerIsPlaying ? 'none'  : 'block';
  document.getElementById('icon-pause').style.display = playerIsPlaying ? 'block' : 'none';
}

function updateArtSpin() {
  const art = document.getElementById('player-art');
  art.classList.toggle('spinning', playerIsPlaying);
}

function prevSong() {
  if (playerShuffle) {
    const pos = playerShuffleOrder.indexOf(playerCurrentIndex);
    const prev = pos > 0 ? playerShuffleOrder[pos - 1] : playerShuffleOrder[playerShuffleOrder.length - 1];
    loadTrack(prev);
  } else {
    loadTrack(playerCurrentIndex - 1);
  }
  if (playerIsPlaying) audio().play().catch(() => {});
}

function nextSong() {
  if (playerRepeat) {
    audio().currentTime = 0;
    if (playerIsPlaying) audio().play().catch(() => {});
    return;
  }
  if (playerShuffle) {
    const pos = playerShuffleOrder.indexOf(playerCurrentIndex);
    const next = pos < playerShuffleOrder.length - 1 ? playerShuffleOrder[pos + 1] : playerShuffleOrder[0];
    loadTrack(next);
  } else {
    loadTrack(playerCurrentIndex + 1);
  }
  if (playerIsPlaying) audio().play().catch(() => {});
}

function toggleShuffle() {
  playerShuffle = !playerShuffle;
  document.getElementById('btn-shuffle').classList.toggle('active-mode', playerShuffle);
  if (playerShuffle) playerShuffleOrder = buildShuffleOrder(playerCurrentPlaylist.tracks.length);
}

function toggleRepeat() {
  playerRepeat = !playerRepeat;
  document.getElementById('btn-repeat').classList.toggle('active-mode', playerRepeat);
}

function buildShuffleOrder(n) {
  const arr = Array.from({ length: n }, (_, i) => i);
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

function stopPlayer() {
  const a = audio();
  a.pause();
  a.src = '';
  playerIsPlaying = false;
  updatePlayPauseIcon();
  updateArtSpin();
}

// ── Seek ──
function seekAudio(e) {
  const a = audio();
  if (!a.duration) return;
  const bar  = document.getElementById('player-progress-bar');
  const rect = bar.getBoundingClientRect();
  const pct  = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
  a.currentTime = pct * a.duration;
}

function fmtTime(s) {
  if (isNaN(s)) return '0:00';
  const m = Math.floor(s / 60);
  const sec = Math.floor(s % 60);
  return m + ':' + (sec < 10 ? '0' : '') + sec;
}

// ── Audio events ──
document.addEventListener('DOMContentLoaded', () => {
  const a = audio();
  a.addEventListener('timeupdate', () => {
    if (!a.duration) return;
    const pct = (a.currentTime / a.duration) * 100;
    document.getElementById('player-progress-fill').style.width = pct + '%';
    document.getElementById('player-progress-thumb').style.left = pct + '%';
    document.getElementById('player-current').textContent = fmtTime(a.currentTime);
  });
  a.addEventListener('loadedmetadata', () => {
    document.getElementById('player-duration').textContent = fmtTime(a.duration);
  });
  a.addEventListener('ended', () => {
    playerIsPlaying = false;
    nextSong();
    audio().play().catch(() => {});
  });
  a.addEventListener('play',  () => { playerIsPlaying = true;  updatePlayPauseIcon(); updateArtSpin(); });
  a.addEventListener('pause', () => { playerIsPlaying = false; updatePlayPauseIcon(); updateArtSpin(); });
});

/* ============================================================
   TOGETHER SINCE COUNTER
   ============================================================ */
(function () {
  const START = new Date('2023-05-30T00:00:00');

  function update() {
    const now  = new Date();
    let   y    = now.getFullYear()  - START.getFullYear();
    let   mo   = now.getMonth()     - START.getMonth();
    let   d    = now.getDate()      - START.getDate();
    if (d  < 0) { mo--; const prev = new Date(now.getFullYear(), now.getMonth(), 0); d  += prev.getDate(); }
    if (mo < 0) { y--;  mo += 12; }
    const h  = now.getHours();
    const mi = now.getMinutes();
    const s  = now.getSeconds();

    function set(id, val) {
      const el = document.getElementById(id);
      if (!el) return;
      const str = String(val);
      if (el.textContent === str) return;

      // Step 1: animate out
      el.classList.remove('num-in', 'num-out');
      void el.offsetWidth; // reflow
      el.classList.add('num-out');

      // Step 2: after out, swap value and animate in
      setTimeout(() => {
        el.textContent = str;
        el.classList.remove('num-out');
        void el.offsetWidth;
        el.classList.add('num-in');
        setTimeout(() => el.classList.remove('num-in'), 350);
      }, 160);
    }

    set('tc-years',   y);
    set('tc-months',  mo);
    set('tc-days',    d);
    set('tc-hours',   h);
    set('tc-minutes', mi);
    set('tc-seconds', s);

    set('hc-years',   y);
    set('hc-months',  mo);
    set('hc-days',    d);
    set('hc-hours',   h);
    set('hc-minutes', mi);
    set('hc-seconds', s);
  }

  document.addEventListener('DOMContentLoaded', () => { update(); setInterval(update, 1000); });
})();